def log_data(logger, data):
    if isinstance(logger, ConsoleLogger):
        logger.log(data)
    elif isinstance(logger, FileLogger):
        logger.write_log(data)
    else:
        raise TypeError('Unsupported logger')

class ConsoleLogger:
    def log(self, data):
        print('Console:', data)

class FileLogger:
    def write_log(self, data):
        print('File:', data)

