challenge.solution:
import json

def export_data(exporter, data):
    exporter.export(data)

class CSVExporter:
    def export(self, data):
        print(','.join(str(x) for x in data))

class JSONExporter:
    def export(self, data):
        print(json.dumps(data))

data = [1, 2, 3]
export_data(CSVExporter(), data)
export_data(JSONExporter(), data)
